1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const COMPONENT_BASE_PRICE = 25;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const COMPONENT_BLOCK_PRICE = 60;
9	
10	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number };
20	type Customer = { yearsWithMHPCO: number };
21	
22	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
23	
24	const mainItemBasePrice = (item: Item): number =>
25	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
26	
27	const componentGroupBasePrice = (count: number): number =>
28	  count === COMPONENT_BLOCK_SIZE
29	    ? COMPONENT_BLOCK_PRICE
30	    : count * COMPONENT_BASE_PRICE;
31	
32	const groupComponentsByType = (items: Item[]): Map<string, number> => {
33	  const groups = new Map<string, number>();
34	  for (const item of items) {
35	    if (!isComponent(item)) continue;
36	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
37	  }
38	  return groups;
39	};
40	
41	const basePremiumGroups = (items: Item[]): number[] => {
42	  const mainItemPremiums = items
43	    .filter((item) => !isComponent(item))
44	    .map(mainItemBasePrice);
45	  const componentGroupPremiums = [...groupComponentsByType(items).values()].map(
46	    componentGroupBasePrice,
47	  );
48	  return [...mainItemPremiums, ...componentGroupPremiums];
49	};
50	
51	const curseSurcharge = (item: Item): number =>
52	  item.cursed ? mainItemBasePrice(item) * CURSE_SURCHARGE_RATE : 0;
53	
54	const highEnchantmentSurcharge = (item: Item): number =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
56	    ? mainItemBasePrice(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
57	    : 0;
58	
59	const itemSurcharges = (items: Item[]): number =>
60	  items.reduce(
61	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
62	    0,
63	  );
64	
65	export const quote = (_customer: Customer, items: Item[]): number => {
66	  const policyBasePremium = basePremiumGroups(items).reduce(
67	    (sum, premium) => sum + premium,
68	    0,
69	  );
70	  const firstInsuranceSurcharge =
71	    policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
72	  const surcharges = itemSurcharges(items);
73	  return Math.ceil(
74	    policyBasePremium + firstInsuranceSurcharge + surcharges + PROCESSING_FEE,
75	  );
76	};
77	
78	export const claim = (..._args: unknown[]): unknown => {
79	  return undefined;
80	};
