11	  });
12	  it("a single amulet yields premium of 71 G (60 base + 6 first + 5 fee)", () => {
13	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }])).toBe(71);
14	  });
15	  it("a single staff yields premium of 93 G (80 base + 8 first + 5 fee)", () => {
16	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff", material: "oak", enchantment: 1, cursed: false }])).toBe(93);
17	  });
18	  it("a single potion yields premium of 49 G (40 base + 4 first + 5 fee)", () => {
19	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion", material: "glass", enchantment: 1, cursed: false }])).toBe(49);
20	  });
21	
22	  // Components
23	  it("a single rune (component) yields premium of 33 G (25 base + 2.5 first + 5 fee → rounded up)", () => {
24	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }])).toBe(33);
25	  });
26	  it("2 runes yield premium of 60 G (50 base + 5 first + 5 fee)", () => {
27	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }])).toBe(60);
28	  });
29	  it("3 runes (block) yield premium of 71 G (60 base + 6 first + 5 fee)", () => {
30	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(71);
31	  });
32	  it("4 runes yield premium of 115 G (100 base + 10 first + 5 fee)", () => {
33	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(115);
34	  });
35	  it("3 runes + 3 moonstones (two blocks) yield premium of 137 G (120 base + 12 first + 5 fee)", () => {
36	    expect(quote({ yearsWithMHPCO: 0 }, [
37	      { type: "rune" }, { type: "rune" }, { type: "rune" },
38	      { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
39	    ])).toBe(137);
40	  });
41	  it("2 runes + 1 moonstone yields premium of 88 G (75 base + 7.5 first + 5 fee → rounded up)", () => {
42	    expect(quote({ yearsWithMHPCO: 0 }, [
43	      { type: "rune" }, { type: "rune" }, { type: "moonstone" },
44	    ])).toBe(88);
45	  });
46	
47	  // Premium modifiers (single item, newcomer)
48	  it("cursed sword (newcomer, enchantment 3) yields premium of 165 G", () => {
49	    expect(quote({ yearsWithMHPCO: 0 }, [
50	      { type: "sword", material: "steel", enchantment: 3, cursed: true },
51	    ])).toBe(165);
52	  });
53	  it("highly enchanted sword (enchantment 5, not cursed, newcomer) yields premium of 145 G", () => {
54	    expect(quote({ yearsWithMHPCO: 0 }, [
55	      { type: "sword", material: "steel", enchantment: 5, cursed: false },
56	    ])).toBe(145);
57	  });
58	  it.todo("sword with enchantment 4 (newcomer, not cursed) yields premium of 115 G (no high-enchantment surcharge)");
59	
60	  // Loyalty discount & follow-up contract
61	  it.todo("long-standing customer (2+ years) with a single sword yields premium of 95 G (100 + 10 first − 20 loyalty + 5 fee)");
62	  it.todo("second contract of a long-standing customer adds the 15% follow-up discount");
63	
64	  // Multi-item policies and modifier scope
65	  it.todo("policy with cursed sword + plain amulet yields premium of 220 G (210 + 16 first + 5 fee ... per integration rules)");
66	
67	  // Quote rounding
68	  it.todo("premium with fractional result is rounded up in MHPCO's favor");
69	
70	  // Claim — basic
71	  it.todo("claim on a sword (steel, enchantment 3) with damage 500 G pays 400 G and remainingCap 1600 G");
72	  it.todo("claim on a rune with damage 200 G pays 100 G (full minus 100 deductible)");
73	
74	  // Claim — special clauses
75	  it.todo("dragon-material sword (enchantment 9) damage 1000 G pays 400 G (50% rule wins then deductible)");
76	  it.todo("dragon-material sword (enchantment 5) damage 800 G pays 700 G (full minus deductible)");
77	  it.todo("steel sword (enchantment 9) damage 1000 G pays 400 G (50% then deductible)");
78	
79	  // Claim — multiple damages
80	  it.todo("claim with two damages (sword + amulet) applies deductible per damage entry");
81	
82	  // Claim — cap and successive claims
83	  it.todo("successive claims exhaust the cap and reduce later payouts");
84	
85	  // CLI / scenario integration
86	  it.todo("scenario with a quote step returns premium in results");
87	  it.todo("scenario with a quote followed by a claim returns premium then payout+remainingCap");
88	  it.todo("unknown item type in quote causes error (rejected)");
89	  it.todo("claim referencing item not in policy is rejected");
90	  it.todo("claim with negative damage amount is rejected");
91	});
